import React , { useState,useEffect }  from "react";
import logo from "./images/logo.jpeg";
import Navbar from 'react-bootstrap/Navbar';
import Container from 'react-bootstrap/Container';
import Nav from 'react-bootstrap/Nav';
import Form from 'react-bootstrap/Form';
import Button from 'react-bootstrap/Button';
import InputGroup from 'react-bootstrap/InputGroup';
import Row from 'react-bootstrap/Row';
import Col from 'react-bootstrap/Col';
import "./upload.css";
import { useNavigate ,Link, Navigate } from 'react-router-dom';



function UploadPage() {
  const navigate = useNavigate();
  const [loading, setLoading] = useState(false);
  const [data ,setData] = useState({search :''});
  const [videos , setVideos] = useState([])



  
  const handleInputChange = (event) => {
    const { name, value } = event.target;
    setData((prevFormData) => ({
      ...prevFormData,
      [name]: value,
    }));
  };
  




  const handleSearch = async (e) => {
    e.preventDefault()

    if (!data.search) {
      alert('Please enter a search term');
      return;
    }

    //setLoading(true);


    try {
      const token = localStorage.getItem('token'); // Retrieve the token
      if (!token) {
        alert('Please log in to perform this action');
        navigate('/')
      }
      const response = await fetch('http://localhost:5000/api/search', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          Authorization: `Bearer ${token}`,
        },
       body: JSON.stringify({ search: data.search }), // Send the search data as JSON
      });

     if (!response.ok) {
        const errorMessage = await response.text();
        throw new Error(errorMessage || 'Failed to search for video');
      }

      const data = await response.json();
      setVideos(data.videos)
      console.log(`${data.message}`);
    } catch (error) {
      console.error('Error uploading PDF:', error);
      alert('An error occurred while Looking for the video. Please try again.');
    } finally {
      setLoading(false);
    } 
  };

  return (
    <div>
<Navbar className="bg-body-tertiary justify-content-between">
<Container>
          <Navbar.Brand href="#home"><img
               src={logo}
              width="30"
              height="30"
              className="d-inline-block align-top"
              alt="React Bootstrap logo"
          /></Navbar.Brand>
          <Navbar.Toggle aria-controls="basic-navbar-nav" />
          <Navbar.Collapse id="basic-navbar-nav">
          <Nav className="me-auto">
          <Nav.Link as={Link} to="/home">Home</Nav.Link>
          <Nav.Link as={Link} to="/">Login</Nav.Link>
          <Nav.Link as={Link} to="/register">Registration</Nav.Link>
          </Nav>
          <Form onSubmit={handleSearch}>
    <Row>
      <Col xs="auto">
        <Form.Control          
          type="text"
          placeholder="Search"
          className="mr-sm-2 search"
          onChange={handleInputChange}
          name="search"
          value={data.search}
        />
      </Col>
      <Col xs="auto">
        <Button type="submit">Search</Button>
      </Col>
    </Row>
  </Form>
          </Navbar.Collapse>
        </Container>

</Navbar>

        <div className="form-container">
      <div className="">
        <h4>Choose a Chapter</h4>


      <div>
        {videos.length > 0 ? (
          <ul>
            {videos.map((video) => (
              <li key={video.id.videoId}>
                <a
                  href={`https://www.youtube.com/watch?v=${video.id.videoId}`}
                  target="_blank"
                  rel="noopener noreferrer"
                >
                  <img
                    src={video.snippet.thumbnails.default.url}
                    alt={video.snippet.title}
                    width="120"
                    height="90"
                  />
                  <div>{video.snippet.title}</div>
                </a>
              </li>
            ))}
          </ul>
        ) : (
          <p>No videos found.</p>
        )}
      </div>
       


        </div>
        

      </div>
    </div>
  );
}

export default UploadPage;
